/* Lightweight pipwerks-compatible SCORM 1.2 wrapper */
(function (window) {
  "use strict";

  var pipwerks = window.pipwerks || (window.pipwerks = {});

  function findAPI(win) {
    var attempts = 0;
    while (win && attempts < 10) {
      try {
        if (win.API) {
          return win.API;
        }
      } catch (e) {
        return null;
      }
      attempts += 1;
      win = win.parent;
    }
    return null;
  }

  var SCORM = {
    version: "1.2",
    handleCompletionStatus: true,
    API: null,
    initialized: false,

    init: function () {
      if (this.initialized) {
        return true;
      }
      this.API = findAPI(window);
      if (!this.API && window.opener) {
        this.API = findAPI(window.opener);
      }
      if (!this.API) {
        return false;
      }
      this.initialized = this.API.LMSInitialize("") === "true";
      return this.initialized;
    },

    get: function (element) {
      if (!this.API || !this.initialized) {
        return "";
      }
      return this.API.LMSGetValue(element);
    },

    set: function (element, value) {
      if (!this.API || !this.initialized) {
        return false;
      }
      return this.API.LMSSetValue(element, String(value)) === "true";
    },

    save: function () {
      if (!this.API || !this.initialized) {
        return false;
      }
      return this.API.LMSCommit("") === "true";
    },

    quit: function () {
      if (!this.API || !this.initialized) {
        return false;
      }
      var ok = this.API.LMSFinish("") === "true";
      this.initialized = false;
      return ok;
    },
  };

  pipwerks.SCORM = SCORM;
})(window);
